  -- Generate code if not provided
  v_code := coalesce(
    nullif(trim(p_coupon_code), ''),
    upper(substring(md5(random()::text) from 1 for 8))
  );

  insert into public.business_coupons (
    bathroom_id, business_user_id, title, description,
