    p_max_redemptions, p_starts_at, p_expires_at, p_premium_only
  )
  returning id into v_coupon_id;

  return jsonb_build_object(
    'success', true,
    'coupon_id', v_coupon_id,
    'coupon_code', v_code
  );
end;
$$;

